rule_results.python_conversion:
def check_sugars_vs_carbohydrates(product):
    left_raw = product.get('sugars')
    right_raw = product.get('carbohydrates')
    try:
        left_value = float(left_raw)
        right_value = float(right_raw)
    except (TypeError, ValueError):
        return None
    if left_value > right_value:
        return 'sugars-greater-than-carbohydrates'
    return None

