rule_results.python_conversion:
def check_fat_over_105g(product: dict) -> str | None:
    """
    Returns the rule tag "fat-value-over-105g" if the product's fat content exceeds 105g,
    otherwise returns None.
    """
    # Retrieve the fat value; if missing or not a number, treat as not failing the rule.
    fat_value = product.get("fat")
    if fat_value is None:
        return None

    try:
        fat_numeric = float(fat_value)
    except (TypeError, ValueError):
        return None

    if fat_numeric > 105.0:
        return "fat-value-over-105g"
    return None

